exports = handleRetry;

async function retryOperation({ fullDocument: logEntry }) {
  // parse values from log entry posted to database
  const { args, retries, functionName, operationId } = logEntry;
  // Re-execute the main function
  await context.functions.execute(functionName, ...args, operationId, retries);
}

exports = retryOperation;

sections.body:
- Authenticate a MongoDB Atlas user:

  Use your [API Access Lists endpoint](atlas-admin-api-access) to
  log in to the App Services CLI:

  ```shell
  appservices login --api-key="<API KEY>" --private-api-key="<PRIVATE KEY>"
  ```

- Pull your App's latest configuration files:

  Run the following command to get a local copy of your configuration files:

  ```shell
  appservices pull --remote=<App ID>
  ```

  By default, the command pulls files into the current working directory. You can
  specify a directory path with the optional `--local` flag.

- Add configuration for the Database Trigger. For more information,
  refer to the [Trigger configuration reference](atlas/app-services/reference/config/triggers).

  ```json
  {
    "name": "retry",
    "type": "DATABASE",
    "config": {
      "operation_types": ["INSERT"],
      "database": "logs",
      "collection": "failed_execution_logs",
      "service_name": "mongodb-atlas",
      "project": {},
      "full_document": true,
      "full_document_before_change": false,
      "unordered": false,
      "skip_catchup_events": false
    },
    "disabled": false,
    "event_processors": {
      "FUNCTION": {
        "config": {
          "function_name": "retryOperationDbTrigger"
        }
      }
    }
  }

  ```

- Now add the code to the functions/config.json Function
  that the Trigger invokes.

  The function `retryOperation` takes as a parameter `logEntry`, the document that the
  retry handler posted to the failed execution tracker collection.
  Then, `retryOperation` uses [context.functions.execute()](atlas/app-services/functions/context)
  to invoke the main function with information from `logEntry`.

  ```js
  [
    // ...other configuration
    {
      "name": "retryOperationDbTrigger",
      "private": true
    }
  ]
  ```

- Add the following code to the file functions/retryOperationDbTrigger.js:

  ```js
  async function retryOperation({ fullDocument: logEntry }) {
    // parse values from log entry posted to database
    const { args, retries, functionName, operationId } = logEntry;
    // Re-execute the main function
    await context.functions.execute(functionName, ...args, operationId, retries);
  }

  exports = retryOperation;

  ```

- Deploy your changes:

  Run the following command to [deploy](atlas/app-services/apps/update) your changes:

  ```shell
  appservices push
  ```

